import re


class ASTNode:
    def __init__(self, type, value=None, op=None, left=None, right=None, operand=None):
        self.type = type
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand


class _Tokenizer:
    def __init__(self, expression):
        self.tokens = re.findall(r'\d+\.?\d*|[+\-*/()]', expression.replace(' ', ''))
        self.pos = 0

    def peek(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self):
        token = self.peek()
        self.pos += 1
        return token


def parse(expression: str) -> ASTNode:
    if not expression or not expression.strip():
        raise ValueError("Empty input")

    tokenizer = _Tokenizer(expression)
    result = _parse_expression(tokenizer)

    if tokenizer.peek() is not None:
        raise ValueError(f"Unexpected token: {tokenizer.peek()}")

    return result


def _parse_expression(tokenizer):
    return _parse_additive(tokenizer)


def _parse_additive(tokenizer):
    left = _parse_multiplicative(tokenizer)

    while tokenizer.peek() in ('+', '-'):
        op = tokenizer.consume()
        right = _parse_multiplicative(tokenizer)
        left = ASTNode(type="binop", op=op, left=left, right=right)

    return left


def _parse_multiplicative(tokenizer):
    left = _parse_primary(tokenizer)

    while tokenizer.peek() in ('*', '/'):
        op = tokenizer.consume()
        right = _parse_primary(tokenizer)
        left = ASTNode(type="binop", op=op, left=left, right=right)

    return left


def _parse_primary(tokenizer):
    token = tokenizer.peek()

    if token is None:
        raise ValueError("Unexpected end of expression")

    if token == '(':
        tokenizer.consume()
        node = _parse_expression(tokenizer)
        if tokenizer.peek() != ')':
            raise ValueError("Unmatched parenthesis")
        tokenizer.consume()
        return node

    if token == '-':
        tokenizer.consume()
        operand = _parse_primary(tokenizer)
        return ASTNode(type="unary", op='-', operand=operand)

    # Number
    tokenizer.consume()
    try:
        return ASTNode(type="number", value=float(token))
    except ValueError:
        raise ValueError(f"Invalid token: {token}")


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        return node.value

    if node.type == "unary":
        if node.op == '-':
            return -evaluate(node.operand)
        raise ValueError(f"Unknown unary operator: {node.op}")

    if node.type == "binop":
        left = evaluate(node.left)
        right = evaluate(node.right)

        if node.op == '+':
            return left + right
        if node.op == '-':
            return left - right
        if node.op == '*':
            return left * right
        if node.op == '/':
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right

        raise ValueError(f"Unknown operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")

import pytest
from expr_parser import parse, evaluate, ASTNode


class TestParseSimpleNumber:
    def test_parse_simple_integer(self):
        node = parse("42")
        assert node.type == "number"
        assert node.value == 42
        assert node.op is None
        assert node.left is None
        assert node.right is None
        assert node.operand is None

    def test_evaluate_simple_integer(self):
        node = parse("42")
        assert evaluate(node) == 42.0

    def test_parse_simple_float(self):
        node = parse("3.14")
        assert node.type == "number"
        assert node.value == 3.14

    def test_evaluate_simple_float(self):
        node = parse("3.14")
        assert evaluate(node) == 3.14


class TestBinaryOperators:
    def test_parse_addition(self):
        node = parse("2 + 3")
        assert node.type == "binop"
        assert node.op == "+"
        assert node.left.type == "number"
        assert node.left.value == 2
        assert node.right.type == "number"
        assert node.right.value == 3

    def test_evaluate_addition(self):
        assert evaluate(parse("2 + 3")) == 5.0

    def test_parse_subtraction(self):
        node = parse("10 - 4")
        assert node.type == "binop"
        assert node.op == "-"

    def test_evaluate_subtraction(self):
        assert evaluate(parse("10 - 4")) == 6.0

    def test_parse_multiplication(self):
        node = parse("3 * 4")
        assert node.type == "binop"
        assert node.op == "*"

    def test_evaluate_multiplication(self):
        assert evaluate(parse("3 * 4")) == 12.0

    def test_parse_division(self):
        node = parse("10 / 2")
        assert node.type == "binop"
        assert node.op == "/"

    def test_evaluate_division(self):
        assert evaluate(parse("10 / 2")) == 5.0


class TestOperatorPrecedence:
    def test_multiplication_before_addition(self):
        # 2 + 3 * 4 = 2 + 12 = 14
        assert evaluate(parse("2 + 3 * 4")) == 14.0

    def test_division_before_subtraction(self):
        # 10 - 6 / 2 = 10 - 3 = 7
        assert evaluate(parse("10 - 6 / 2")) == 7.0

    def test_left_to_right_same_precedence(self):
        # 10 / 2 * 3 = 5 * 3 = 15 (left-to-right)
        assert evaluate(parse("10 / 2 * 3")) == 15.0

    def test_complex_expression(self):
        # 2 + 3 * 4 - 6 / 2 = 2 + 12 - 3 = 11
        assert evaluate(parse("2 + 3 * 4 - 6 / 2")) == 11.0


class TestParentheses:
    def test_simple_parentheses(self):
        # (2 + 3) = 5
        assert evaluate(parse("(2 + 3)")) == 5.0

    def test_parentheses_override_precedence(self):
        # (2 + 3) * 4 = 5 * 4 = 20
        assert evaluate(parse("(2 + 3) * 4")) == 20.0

    def test_nested_parentheses(self):
        # ((2 + 3) * (4 - 1)) = 5 * 3 = 15
        assert evaluate(parse("((2 + 3) * (4 - 1))")) == 15.0

    def test_parentheses_with_division(self):
        # 10 / (2 + 3) = 10 / 5 = 2
        assert evaluate(parse("10 / (2 + 3)")) == 2.0
